import React from "react";
import "./Map.css";

// Color mapping for divisions
const divisionColors = {
  "Konkan": "#6c757d",
  "Pune": "#28a745",
  "Nashik": "#fadb14",
  "Nagpur": "#f0ad4e",
  "Amravati": "#f38fa9"
};

// Districts grouped by division
const divisionDistricts = {
  "Konkan": ["Mumbai", "Thane", "Palghar", "Raigad", "Ratnagiri", "Sindhudurg"],
  "Pune": ["Pune", "Solapur", "Satara", "Sangli", "Kolhapur"],
  "Nashik": ["Nashik", "Ahmednagar", "Jalgaon", "Dhule"],
  "Nagpur": ["Nagpur", "Wardha", "Bhandara", "Gondia", "Chandrapur", "Gadchiroli"],
  "Amravati": ["Akola", "Amravati", "Yavatmal", "Washim", "Buldhana"]
};

const Map = ({ onDistrictClick }) => {
  return (
    <div className="maharashtra-map">
      {Object.keys(divisionDistricts).map(div => 
        divisionDistricts[div].map(district => (
          <div
            key={district}
            className="district"
            style={{ backgroundColor: divisionColors[div] }}
            onClick={() => onDistrictClick(district)}
            title={district}
          >
            {district}
          </div>
        ))
      )}
    </div>
  );
};

export default Map;
